#include <bits/stdc++.h>
using namespace std;
const int mod=1e8;
int n,m,a[13];
long long dp[13][1<<12];
bool check1(int x,int y){
    return !(((x<<1)&x) || ((x>>1)&x) || ((x&a[y])!=x));
}
bool check2(int x,int y){
    return (x&y)==0;
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            int x;
            scanf("%d",&x);
            a[i]=a[i]*2+x;
        }
    for(int i=0;i<1<<m;i++)
        dp[1][i]=check1(i,1);
    for(int i=2;i<=n;i++)
        for(int j=0;j<1<<m;j++)
            if(check1(j,i))
                for(int k=0;k<1<<m;k++)
                    if(check1(k,i-1) && check2(j,k))
                        dp[i][j]+=dp[i-1][k],dp[i][j]%=mod;
    long long ans=0;
    for(int i=0;i<1<<m;i++)
        ans+=dp[n][i],ans%=mod;
    printf("%lld",ans);
    return 0;
}
